import os
from dataclasses import dataclass
from typing import Any, Dict, List, Optional

from ariadne import QueryType, ObjectType, make_executable_schema
from ariadne.asgi import GraphQL
from starlette.applications import Starlette
from starlette.middleware.base import BaseHTTPMiddleware
from starlette.requests import Request
from starlette.responses import JSONResponse, Response
from starlette.routing import Mount


TYPEDEFS = """
scalar JSON

type Query {
  user(username: String!): User
  users: [User!]!
  post(id: ID!): Post
  posts: [Post!]!
}

type User {
  id: ID!
  username: String!
  bio: String

  email: String
  phone: String
  address: String

  posts: [Post!]!
}

type Post {
  id: ID!
  title: String!
  body: String!
  author: User!
}
"""


@dataclass
class UserModel:
  id: str
  username: str
  bio: Optional[str] = None
  email: Optional[str] = None
  phone: Optional[str] = None
  address: Optional[str] = None


@dataclass
class PostModel:
  id: str
  title: str
  body: str
  author_id: str


USERS: Dict[str, UserModel] = {
  "1": UserModel(
    id="1",
    username="alice",
    bio="I like graphs.",
    email="alice@example.com",
    phone="+1-555-0101",
    address="1 Main St, Example City",
  ),
  "2": UserModel(
    id="2",
    username="bob",
    bio="Coffee & code.",
    email="bob@example.com",
    phone="+1-555-0102",
    address="2 Main St, Example City",
  ),
}

POSTS: Dict[str, PostModel] = {
  "101": PostModel(id="101", title="Hello GraphQL", body="First post", author_id="1"),
  "102": PostModel(id="102", title="Ariadne Tips", body="Use resolvers", author_id="1"),
  "201": PostModel(id="201", title="Starlette", body="ASGI is nice", author_id="2"),
}

USERNAME_INDEX: Dict[str, str] = {u.username: u.id for u in USERS.values()}


def get_user_by_id(user_id: str) -> Optional[UserModel]:
  return USERS.get(user_id)


def get_user_by_username(username: str) -> Optional[UserModel]:
  uid = USERNAME_INDEX.get(username)
  return USERS.get(uid) if uid else None


def get_posts_by_author_id(author_id: str) -> List[PostModel]:
  return [p for p in POSTS.values() if p.author_id == author_id]


def get_post_by_id(post_id: str) -> Optional[PostModel]:
  return POSTS.get(str(post_id))


class AuthMiddleware(BaseHTTPMiddleware):
  async def dispatch(self, request: Request, call_next):
    username = request.headers.get("x-user")
    if username:
      request.state.current_user = get_user_by_username(username)
    else:
      request.state.current_user = None
    return await call_next(request)


query = QueryType()
user_obj = ObjectType("User")
post_obj = ObjectType("Post")


@query.field("user")
def resolve_user(*_, username: str, **__):
  return get_user_by_username(username)


@query.field("users")
def resolve_users(*_):
  return list(USERS.values())


@query.field("post")
def resolve_post(*_, id: Any, **__):
  return get_post_by_id(str(id))


@query.field("posts")
def resolve_posts(*_):
  return list(POSTS.values())


@user_obj.field("posts")
def resolve_user_posts(obj: Any, *_):
  user_id = getattr(obj, "id", None) or (obj.get("id") if isinstance(obj, dict) else None)
  if not user_id:
    return []
  return get_posts_by_author_id(str(user_id))


@post_obj.field("author")
def resolve_post_author(obj: Any, *_):
  author_id = getattr(obj, "author_id", None) or (obj.get("author_id") if isinstance(obj, dict) else None)
  if not author_id:
    return None
  return get_user_by_id(str(author_id))


def context_value(request: Request) -> Dict[str, Any]:
  return {
    "request": request,
    "current_user": getattr(request.state, "current_user", None),
  }


schema = make_executable_schema(TYPEDEFS, [query, user_obj, post_obj])

graphql_app = GraphQL(
  schema,
  debug=os.getenv("DEBUG", "1") == "1",
  context_value=context_value,
)

app = Starlette()
app.add_middleware(AuthMiddleware)
app.routes.append(Mount("/graphql", graphql_app))


